INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("加速の玉飾り", 1, 0, 11001, 11001, "ＴＰ上昇＋5", 1800, 10, 1, 1, "迷宮内で見つかったイヤリング。\n装備者に活力加速を与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("水蓮の盾", 1, 0, 11002, 11002, "ダメージを受けるたびＴＰ100回復（最大１回）", 1800, 10, 1, 1, "迷宮内で見つかった円盾。受けた\n攻撃をエネルギーに変換できる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("青輝の環", 1, 0, 11003, 11003, "バトル開始時ＴＰ100回復", 1800, 10, 1, 1, "迷宮内で見つかった腕輪。戦いの\n始まりとともに、装備者にエネル\nギーを与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("冷玉の杖", 1, 0, 11004, 11004, "ＴＰ消費軽減＋2", 1800, 10, 1, 1, "迷宮内で⾒つかった杖。装備者に\n力を温存させる効果をもたらす。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("風渡りの靴", 1, 0, 11005, 11005, "重複可能の行動速度＋10％", 1800, 10, 1, 1, "迷宮内で⾒つかった靴。装備した\n者は迅速に動くことができる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("紫晶ビザリオ", 2, 0, 12001, 12001, "状態異常命中＋20", 1800, 10, 1, 1, "迷宮内で見つかった首飾り。\n敵に異常を与えやすくなる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("魔杖メジナエ", 2, 0, 12002, 12002, "敵全体に呪い付与（毎秒【弱体】数×500ダメージ）", 1800, 10, 1, 1, "迷宮内で見つかった杖。所持する\nだけで敵を呪うことができる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("暗剣ポワゾン", 2, 0, 12003, 12003, "敵全体に毒付与（毎秒【弱体】数×500ダメージ）", 1800, 10, 1, 1, "迷宮内で見つかった短剣。持つだ\nけで敵を毒にすることができる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("破守帽ディスペル", 2, 0, 12004, 12004, "敵の物理/魔法攻撃力－10％", 1800, 10, 1, 1, "迷宮内で見つかった帽子。装備す\nると敵の攻撃を弱体させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("崩刀ヤマツキ", 2, 0, 12005, 12005, "敵の物理/魔法防御力－10％", 1800, 10, 1, 1, "迷宮内で見つかった刀。\n敵の守りを断ち崩す力がある。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("キラースピア", 3, 0, 13001, 13001, "敵の物理/魔法被クリダメ＋10％", 1800, 10, 1, 1, "迷宮内で見つかった槍。鋭い一撃\nで敵に深い傷を負わせる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ハナミノカタナ", 3, 0, 13002, 13002, "物理/魔法クリダメ＋10％", 1800, 10, 1, 1, "迷宮内で見つかった刀。致命の攻\n撃を与えたときの威力を高める。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("クリーヴフィスト", 3, 0, 13003, 13003, "通常攻撃強化＋30", 1800, 10, 1, 1, "迷宮内で見つかった籠手。強化\nされた一撃を放つことができる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("クリティカルアーク", 3, 0, 13004, 13004, "物理/魔法クリティカル＋10％", 1800, 10, 1, 1, "迷宮内で⾒つかった⼸。装備する\nと致命の一射を与えやすくなる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("アブゾーブハチェット", 3, 0, 13005, 13005, "ＨＰ吸収＋10", 1800, 10, 1, 1, "迷宮内で見つかった斧。攻撃と共\nに敵の体力を吸い取る力を宿す。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("強化のジェム", 4, 0, 14001, 14001, "バフ強化＋30", 1800, 10, 1, 1, "迷宮内で見つかった耳飾り。装備\n者の強化効果を高める。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("抗鉄のプレート", 4, 0, 14002, 14002, "物理/魔法攻撃力アップ\n（先頭キャラの物理防御力×5）", 1800, 10, 1, 1, "迷宮内で⾒つかった鎧。同朋の\n強靭を、自身の攻撃に変換する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("抗魔のドレス", 4, 0, 14003, 14003, "物理/魔法攻撃力アップ\n（先頭キャラの魔法防御力×5）", 1800, 10, 1, 1, "迷宮内で⾒つかったドレス。装備\n者の抗魔の才を攻撃⼒に換える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("蛇紋のツルギ", 4, 0, 14004, 14004, "物理/魔法攻撃力＋20％", 1800, 10, 1, 1, "迷宮内で見つかった大剣。装備者\nの攻撃力を強化する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("防守のメイル", 4, 0, 14005, 14005, "物理/魔法防御力＋10％", 1800, 10, 1, 1, "迷宮内で見つかった鎧。装備者の\n守りの力を高めることができる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("回生杖", 5, 0, 15001, 15001, "回復強化＋10", 1800, 10, 1, 1, "迷宮内で⾒つかった杖。\n癒しの⼒を高めてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("豊命輪", 5, 0, 15002, 15002, "ＨＰ＋10％", 1800, 10, 1, 1, "迷宮内で見つかった指輪。\n装備者の生命力を強化する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("鉄防甲", 5, 0, 15003, 15003, "15秒ごとに物理無効バリア展開（【守備】数×500無効）", 1800, 10, 1, 1, "迷宮内で見つかった鎧。\n装備者を物理攻撃から守る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("魔封衣", 5, 0, 15004, 15004, "15秒ごとに魔法無効バリア展開（【守備】数×500無効）", 1800, 10, 1, 1, "迷宮内で見つかったローブ。\n装備者を魔法攻撃から守る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("再生ノ腕輪", 5, 0, 15005, 15005, "継続ＨＰ回復（毎秒【守備】数×500回復）", 1800, 10, 1, 1, "迷宮内で見つかった腕輪。\n装備者に再生の力を与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("流烈の耳飾り", 1, 0, 21001, 21001, "ＴＰ上昇＋10", 2800, 10, 2, 2, "迷宮内部で発見された耳飾りの形\nをした遺物。流水の激しさのよう\nに、活力加速を増幅させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("星涙の輝盾", 1, 0, 21002, 21002, "ダメージを受けるたびＴＰ100回復（最大２回）", 2800, 10, 2, 2, "迷宮内部で発見された円盾の形を\nした遺物。装備者に星の癒しを与\nえ攻撃をエネルギーに変換する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("蒼珠の腕輪", 1, 0, 21003, 21003, "バトル開始時ＴＰ200回復", 2800, 10, 2, 2, "迷宮内部で発⾒された腕輪の遺物\nあしらわれた蒼珠が、敵を感知し\n力を授ける。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("星明りの儀杖", 1, 0, 21004, 21004, "ＴＰ消費軽減＋4", 2800, 10, 2, 2, "迷宮内部で発⾒された杖の遺物。\n封じられた星々の神秘が、力の消\n耗を肩代わりしてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("疾風の翼靴", 1, 0, 21005, 21005, "重複可能の行動速度＋20％", 2800, 10, 2, 2, "迷宮内部で発見された、翼の生え\nた靴形の遺物。装備した者に疾風\nの力を施し、行動を速める。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("闇至宝アノマリーラ", 2, 0, 22001, 22001, "状態異常命中＋40", 2800, 10, 2, 2, "迷宮内部で発⾒された、⾸飾りの\n遺物。宝⽯の輝きで敵を虜にし、\n怪異をもたらすという。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("邪眼杖ドゥーム", 2, 0, 22002, 22002, "敵全体に呪い付与（毎秒【弱体】数×1000ダメージ）", 2800, 10, 2, 2, "迷宮内部で発見された、杖の形を\nした遺物。杖先のコアから流れる\n邪気が敵に呪いを付与する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("影刃剣プラール", 2, 0, 22003, 22003, "敵全体に毒付与（毎秒【弱体】数×1000ダメージ）", 2800, 10, 2, 2, "迷宮内部で発見された、短剣の形\nをした遺物。刃に仕込まれた毒が\n気化し、接敵と共に毒を与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("薔薇飾帽イレース", 2, 0, 22004, 22004, "敵の物理/魔法攻撃力－20％", 2800, 10, 2, 2, "迷宮内部で発見された、帽子の形\nをした遺物。絡みつく茨の様に、\n敵の攻撃力を阻害する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("斬赤刃ディバイド", 2, 0, 22005, 22005, "敵の物理/魔法防御力－20％", 2800, 10, 2, 2, "迷宮内部で発⾒された、⼑の遺物\n血で⾚く染まった⼑⾝で、敵の装\n甲をたやすく断ち割る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("フェイタリティ", 3, 0, 23001, 23001, "敵の物理/魔法被クリダメ＋20％", 2800, 10, 2, 2, "迷宮内部で発見された、槍の遺物\n特殊な形の穂先が、敵により深い\n傷を刻み込む。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("クレナイノタチ", 3, 0, 23002, 23002, "物理/魔法クリダメ＋20％", 2800, 10, 2, 2, "迷宮内部で発見された、刀の形を\nした遺物。秋の紅を映す美しき刃\nは致命の攻撃をさらに強化する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ラプチャーガントレット", 3, 0, 23003, 23003, "通常攻撃強化＋60", 2800, 10, 2, 2, "迷宮内部で発⾒された籠⼿の遺\n物。装備者は研ぎ澄まされた強\n力な一撃を放つことができる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("スカイストライク", 3, 0, 23004, 23004, "物理/魔法クリティカル＋20％", 2800, 10, 2, 2, "迷宮内部で発⾒された、⼸の遺物\n装備者は烈⾵の⼒を授かり、獲物\nの急所を貫きやすくなる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("インヘイルアックス", 3, 0, 23005, 23005, "ＨＰ吸収＋20", 2800, 10, 2, 2, "迷宮内部で発⾒された斧の遺物。\n繰り出される⼀撃は、掠めるだけ\nで獲物の魂を吸い取る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("進化のイヤリング", 4, 0, 24001, 24001, "バフ強化＋60", 2800, 10, 2, 2, "迷宮内部で発見された、耳飾りの\n形をした遺物。魔石に込められた\n魔力が強化の力を増幅させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("紅反鋼のアーマー", 4, 0, 24002, 24002, "物理/魔法攻撃力アップ\n（先頭キャラの物理防御力×10）", 2800, 10, 2, 2, "迷宮内部で発⾒された、鎧の遺物\n紅き鋼の加護は、守備力を攻撃力\nへと変換する力を持つ。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("聖減術のテラドレス", 4, 0, 24003, 24003, "物理/魔法攻撃力アップ\n（先頭キャラの魔法防御力×10）", 2800, 10, 2, 2, "迷宮内部で発⾒された、ドレスの\n遺物。精霊の加護が、防魔結界か\nら力を集めてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("炎王のグレートソード", 4, 0, 24004, 24004, "物理/魔法攻撃力＋40％", 2800, 10, 2, 2, "迷宮内部で発見された、大剣の形\nをした遺物。湧き出る炎の力が、\n攻撃の能力を大きく高める。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("桜堅牢のコート", 4, 0, 24005, 24005, "物理/魔法防御力＋20％", 2800, 10, 2, 2, "迷宮内部で発⾒された鎧の遺物。\n千年咲く桜の如く、盤石な堅牢さ\nを装備者に与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("創世緑杖", 5, 0, 25001, 25001, "回復強化＋20", 2800, 10, 2, 2, "迷宮内部で発⾒された杖の遺物。\n装備者に⼤樹の恵みを施し、治癒\n術の才覚を授けてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("空命護珠", 5, 0, 25002, 25002, "ＨＰ＋20％", 2800, 10, 2, 2, "迷宮内部で発見された、指輪の形\nをした遺物。装備者を天空の護り\nで包み込み生命力を増幅させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("鋼装堅鎧", 5, 0, 25003, 25003, "15秒ごとに物理無効バリア展開（【守備】数×1000無効）", 2800, 10, 2, 2, "迷宮内部で発見された、鎧の形を\nした遺物。高度な技術で精錬され\nた鋼は、物理攻撃から身を護る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("魔護霊装", 5, 0, 25004, 25004, "15秒ごとに魔法無効バリア展開（【守備】数×1000無効）", 2800, 10, 2, 2, "迷宮内部で発⾒された、ローブの\n遺物。神樹の蔦が織り込まれ、装\n備者を魔法から護る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("緑護ノ盾輪", 5, 0, 25005, 25005, "継続ＨＰ回復（毎秒【守備】数×1000回復）", 2800, 10, 2, 2, "迷宮内部で発⾒された、腕輪の遺\n物。溢れ出す⾃然の⼒は装備者に\n生命の息吹をもたらす。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("エレメントサージオーブ", 0, 0, 30001, 30001, "属性ボーナス＋100％", 3800, 10, 3, 0, "迷宮中枢部に隠された黎明の秘宝\nデータ保管のため属性の⼒の断⽚\nが封じられており、内なるアスト\nラルを著しく上昇させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("瞬閃蝶の月飾り", 1, 0, 31001, 31001, "ＴＰ上昇＋15", 3800, 10, 3, 3, "迷宮の奥深くに眠っていた月を象\nる耳飾り。内部から発する魔力は\n装備者に蝶のような瞬麗さを授け\n活力加速を大きく上昇させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("海宝華の煌盾", 1, 0, 31002, 31002, "ダメージを受けるたびＴＰ100回復（最大３回）", 3800, 10, 3, 3, "迷宮の奥深くに眠る宝石を飾った\n円盾。海のような青き魔力は装備\n者に庇護を与え、迫り来る脅威す\nらエネルギーへと昇華させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("碧貴石の聖輪", 1, 0, 31003, 31003, "バトル開始時ＴＰ300回復", 3800, 10, 3, 3, "迷宮の奥深くに眠る聖なる腕輪。\n失われた技術で装飾された宝石が\n装備者に加護を齎し、危機が迫る\nと膨大な力を分け与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("永天鏡の王笏", 1, 0, 31004, 31004, "ＴＰ消費軽減＋6", 3800, 10, 3, 3, "迷宮の奥深くに眠る、かつて天界\nに伝えられし杖。天にかざすと鏡\n⽟に篭められた祈りが溢れ出して\n尽きることなき力を授ける。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("熾天使の翔靴", 1, 0, 31005, 31005, "重複可能の行動速度＋30％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、天使の加護\nを宿した戦靴。装備するだけで神\n性を授かり、天使のような自在さ\nで空を翔ることができる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("風神の護風恩寵", 1, 0, 31006, 31006, "ＴＰ上昇＋100", 9999, 10, 3, 5, "迷宮最奥部に鎮祀されし神業の遺\n物。風を司る神々の恩寵が宿され\nており、装備者は無尽蔵の活力が\n疾風の如き速さで体を駆け巡る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("幻獣飾テンタシオン", 2, 0, 32001, 32001, "状態異常命中＋60", 3800, 10, 3, 3, "迷宮の奥深くに眠る、幻獣を象る\n首飾り。この宝石の神秘に魅せら\nれた者は、一切の異変や脅威に抗\nうことができなくなってしまう。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("深淵蝕杖マリディクト", 2, 1, 32002, 32002, "敵全体に呪い付与（毎秒【弱体】数×1500ダメージ）", 3800, 10, 3, 3, "迷宮の奥深くに眠る、月を蝕む杖\n存在するだけで、絶えず呪力の奔\n流を溢れさせ、近づく全ての敵を\n呪いで浸食していく。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("滅刻凶刃ヴェノマス", 2, 0, 32003, 32003, "敵全体に毒付与（毎秒【弱体】数×1500ダメージ）", 3800, 10, 3, 3, "迷宮の奥深くに眠る、黒刃の刺剣\n刃に埋め込まれた宝玉が、絶え間\nなく邪毒を撒き散らし、破滅へと\n刻々と時を数える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("燦然御纏アノラ・ベイラ", 2, 0, 32004, 32004, "敵の物理/魔法攻撃力－30％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、宝飾をあし\nらったベール。蔽布の下から滲み\n出るオーラが、相手の敵意を解き\nほぐし、無力化させてしまう。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("断壁鎖刃フラグメント", 2, 0, 32005, 32005, "敵の物理/魔法防御力－30％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、⼑⾝に鎖を\n這わせた妖⼑。主の意思に逆らい\n暴れる鎖が怨敵の守りを打ち崩し\n紫黒の凶刃が悉くを断ち斬る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("霜影虚装アビスモナーク", 2, 0, 32006, 32006, "敵の物理/魔法与ダメ－25％\n敵の物理/魔法被ダメ＋25％", 9999, 10, 3, 5, "迷宮深層部に静眠せし虚影の装衣\n深淵から出でし蝕影は、存在全て\nを霜雪の如く凍てつかせ、抗う敵\nの剣盾両翼を虚壊させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("リーサルハルバード", 3, 0, 33001, 33001, "敵の物理/魔法被クリダメ＋30％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、地神の力を\n宿した烈槍。大地の力を糧に放つ\n無比の一閃は、地に立つすべての\n敵に甚大なダメージを与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("オオトリノカタナ", 3, 0, 33002, 33002, "物理/魔法クリダメ＋30％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、伝説に語ら\nれる極みの一振り。鳳凰の力を宿\nした真紅の刃は、焔の如き赫く激\n烈な一撃を与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("アースデストラクション", 3, 0, 33003, 33003, "通常攻撃強化＋90", 3800, 10, 3, 3, "迷宮の奥深くに眠る、地核のエネ\nルギーを封じた籠手。振るう一撃\nは、世界を破壊するかの如く、通\n常攻撃を大きく強化する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ジャッジメントアロー", 3, 0, 33004, 33004, "物理/魔法クリティカル＋30％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、咎⼈を裁き\nし聖⼸。この弓に選ばれし装備者\nは神⾵の加護を得て、対象に慈悲\nを与えず一瞬で急所を射貫く。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ザ・ハーヴェスト", 3, 0, 33005, 33005, "ＨＰ吸収＋30", 3800, 10, 3, 3, "迷宮の奥深くに眠る、金色の⼤戦\n斧。刈り取った獲物の魂を糧に、\nその絢爛なる刃は燦燦と輝きを増\nしてゆく。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("セレスティアルエイジ", 3, 0, 33006, 33006, "通常攻撃強化＋500\nＨＰ吸収＋50", 9999, 10, 3, 5, "迷宮最深部に残された久遠の遺物\n神代の大戦より聖騎士に脈々と受\nけ継がれ、装備者へ戦いの記憶と\nともに不滅の力を分け与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("極醒のアミュレット", 4, 0, 34001, 34001, "バフ強化＋90", 3800, 10, 3, 3, "迷宮の奥深くに眠る、炎天の魔力\nを封じた耳飾り。潜在能力を究極\nまで呼び覚まし、強化の力を大幅\nに上昇させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("断刃拒絶のアルギュロス", 4, 0, 34002, 34002, "物理/魔法攻撃力アップ\n（先頭キャラの物理防御力×15）", 3800, 10, 3, 3, "迷宮の奥深くに眠る、⽩⾦の鎧。\n⽩⻯の鱗を繋ぎ合わせた外装が盟\n友の力を集結させる効果を持ち強\n力無比な一撃を可能にする。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("緋華栄華のグラナート", 4, 0, 34003, 34003, "物理/魔法攻撃力アップ\n（先頭キャラの魔法防御力×15）", 3800, 10, 3, 3, "迷宮の奥深くに眠る、栄華の象徴\nとして仕立てられたドレス。深紅\nに咲き乱れる花の加護は、装備者\nの絶魔の⼒を攻撃⼒へ変換する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("覇光帝龍のグローリア", 4, 0, 34004, 34004, "物理/魔法攻撃力＋60％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、光⿓の⼒を\n授かりし⼤剣。その⼀振りはかつ\nての栄光の羽ばたきを想起させ、\n極限の覇気を世界に放つ。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("華舞玲瓏のハルナデシコ", 4, 0, 34005, 34005, "物理/魔法防御力＋30％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、東の国に伝\nわりし聖鎧。玉の様に透き通る輝\nきを放つ鎧は、装備者に華の加護\nを授け、守護の力を高める。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("天戴冠のゼニスブレード", 4, 0, 34006, 34006, "バトル開始時、物理/魔法攻撃力アップフィールド展開\n（現在値＋50％）", 9999, 10, 3, 5, "迷宮深淵部に佇む歴戦無敗の⼤剣\n台座から剣を⼿にした者は天その\nものを冠すかの如き全能感を得て\n千軍を容易く退ける剛⼒を得る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("妖精霊杖・癒光", 5, 0, 35001, 35001, "回復強化＋30", 3800, 10, 3, 3, "迷宮の奥深くに眠る、妖精の輝き\nを封じた杖。宝⽟から無限の⽣命\n⼒が溢れ出し、増幅された快癒の\n⼒であらゆる苦しみを取り除く。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("泉湧命環・豊穣", 5, 0, 35002, 35002, "ＨＰ＋30％", 3800, 10, 3, 3, "迷宮の奥深くに眠る、翠緑に彩ら\nれた指輪。装備者に、かつて豊穣\nに溢れた楽園の光景を想起させ、\n際限なき⽣命⼒を与える。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("白光輝鎧・断壁", 5, 0, 35003, 35003, "15秒ごとに物理無効バリア展開（【守備】数×1500無効）", 3800, 10, 3, 3, "迷宮の奥深くに眠る、白金の輝き\nを放つ鎧。顕現する翅は、意思を\n持つかのよう、装備者に呼応して\n物理攻撃を断つ障壁を展開する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("幽玄煌装・絶魔", 5, 0, 35004, 35004, "15秒ごとに魔法無効バリア展開（【守備】数×1500無効）", 3800, 10, 3, 3, "迷宮の奥深くに眠る、幽庵の煌き\nを宿す鎧。顕現する翅は、意思を\n持つかのよう、装備者に呼応して\n魔法攻撃を絶つ障壁を展開する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("輪廻ノ翡翠珠輪", 5, 0, 35005, 35005, "継続ＨＰ回復（毎秒【守備】数×1500回復）", 3800, 10, 3, 3, "迷宮の奥深くに眠る、翠宝玉をあ\nしらった腕輪。常に滾々とマナが\n湧き出し、生命力を湛え続ける。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("天命授環・伊邪那", 5, 0, 35006, 35006, "ＨＰ＋100％", 9999, 10, 3, 5, "迷宮最下層に供奉された伝承の環\n選ばれし者がひとたび⼿にすれば\n創造神話の如く、千万無量の⽣命\n⼒を齎すと云われる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("プリンセスフォース", 5, 0, 40001, 40001, "ＨＰ＋15％\n物理/魔法与ダメ＋15％", 3200, 10, 3, 1, "【美⾷殿】と共に迷宮を冒険する\nための遺物。王家の装備を精巧に\n模しており、味方の⾝体能⼒を⼤\nきく向上させてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("アストラルブースト", 4, 0, 40002, 40002, "属性ボーナス＋50％", 3200, 10, 3, 1, "【トゥインクルウィッシュ】と共\nに迷宮を冒険するための遺物。\n３人のアストラルに呼応して、属\n性の力を増幅させてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("サレンディアエンゲージ", 1, 0, 40003, 40003, "ショップの販売価格－10％", 3200, 10, 3, 1, "【サレンディア救護院】と共に迷\n宮を冒険するための遺物。主人が\n築いた信頼関係のおかげで、商品\nの価格を値引きしてもらえる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ナイツオブフェイス", 3, 0, 40004, 40004, "物理/魔法クリダメ＋50％\n物理/魔法クリティカル－25％", 3200, 10, 3, 1, "【王宮騎士団】と共に迷宮を冒険\nするための遺物。団長の愛⽤品を\n模し会⼼率と引き換えに、会⼼時\nの威⼒を⾼めてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ラビリンスオーソリティ", 2, 0, 40005, 40005, "挑戦開始時にラビリスタが加入", 3200, 10, 3, 1, "【ラビリンス】と共に迷宮を冒険\nするための遺物。迷宮女王はその\n権能でナイトがどこに居ようとも\n即座に参戦してくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("イルミネイトカルミナ", 4, 0, 40006, 40006, "物理/魔法攻撃力＋15％\nバフ強化＋15", 3200, 10, 3, 1, "【カルミナ】と共に迷宮を冒険す\nるための遺物。これを振るう者の\n熱き声援は、ステージに立つ者の\n能力をより一層高めてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ブルートナハト", 1, 0, 40007, 40007, "敵のＴＰ上昇－15", 3200, 10, 3, 1, "【悪魔偽王国軍】と共に迷宮を冒\n険するための遺物。紅き両刃から\n禍々しく迸る魔力の前では、いか\nなる敵だろうと戦意を失う。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("エリザベスガーディアン", 5, 0, 40008, 40008, "バトル開始時に最もＨＰが多いキャラが敵を挑発", 3200, 10, 3, 1, "【牧場】と共に迷宮を冒険するた\nめの遺物。被ったらたちまちその\n場で最も目立つ存在となり、すべ\nての攻撃を引きつけてしまう。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ノブレスウィスタリア", 3, 0, 40009, 40009, "初期アルファルピ+3000\nアルファルピ獲得量－10%", 3200, 10, 3, 1, "【メルクリウス財団】と共に迷宮\nを冒険するための遺物。人から決\nして多く受け取らず、生まれ持っ\nた財のみで戦いぬく高潔さの証。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("兵法二海一流", 2, 0, 40010, 40010, "デバフ強化＋20", 3200, 10, 3, 1, "【トワイライトキャラバン】と共\nに迷宮を冒険するための遺物。二\n本の刀が見せる煌めきは、悪党ど\nもの気炎を容易く挫く。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("絆のリボン", 3, 0, 40011, 40011, "挑戦開始時にミソギ＆ミミ＆キョウカが加入", 3200, 10, 3, 1, "【リトルリリカル】と共に迷宮を\n冒険するための遺物。中に宿って\nいる強い絆が、どこにいても３人\nをふたたび繋いでくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("琉球犬甲唄", 4, 0, 40012, 40012, "バトル開始時に先頭キャラに物理/魔法防御力+50%", 3200, 10, 3, 1, "【自警団】と共に迷宮を冒険する\nための遺物。護りの奥義が記され\nており、読み込めば攻撃から身を\n守る技術を得ることができる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("フォレストハーモニー", 5, 0, 40013, 40013, "バトル開始時に調和状態", 3200, 10, 3, 1, "【フォレスティエ】と共に迷宮を\n冒険するための遺物。森の息吹を\n内に秘め、所持しているだけで味\n方に調和の力を授ける。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("チャームファタール", 2, 0, 40014, 40014, "1秒ごとに誘惑状態の敵に最大ＨＰの5％の魔法割合ダメージ（最大50万ダメージ）", 3200, 10, 3, 1, "【ルーセント学院】と共に迷宮を\n冒険するための遺物。誘惑した相\n手の生気を少しずつ削ぎ、気付か\nぬ間に甘い終焉を迎えさせる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("プリンセスエンチャント", 4, 0, 50001, 50001, "物理/魔法攻撃力アップ（加入キャラ数×4％、最大100％）", 3200, 10, 3, 1, "【美⾷殿】と共に迷宮を冒険する\nための遺物。冒険の道中で絆を結\nべば結ぶほどに、味⽅の攻撃⼒を\n⾼めてくれる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("トゥインクルブレス", 5, 1, 50002, 50002, "ボスバトルを除いて一度だけバトル敗北を免除", 3200, 10, 3, 1, "【トゥインクルウィッシュ】と共\nに迷宮を冒険するための遺物。ギ\nルドマスターの諦めない心が、味\n方を一度だけ敗北から守る。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("サレンディアノーブル", 3, 0, 50003, 50003, "通常攻撃強化アップ（アルファルピ所持数×0.01、最大100）", 3200, 10, 3, 1, "【サレンディア救護院】と共に迷\n宮を冒険するための遺物。主人の\n気品を漂わせる剣は、築いた富を\n⼒に変転させる効果を持つ。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("レジーナガーラ", 2, 0, 50004, 50004, "敵の物理/魔法被ダメ＋25％\n味方の物理/魔法被ダメ＋25％", 3200, 10, 3, 1, "【王宮騎士団】と共に迷宮を冒険\nするための遺物。副団長の催す闘\n争の宴は、敵味⽅が受けるダメー\nジをみな悉く増加させる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("マスターオブラビリンス", 1, 0, 50005, 50005, "挑戦開始時にランダムな★1の迷宮遺物を１個獲得", 3200, 10, 3, 1, "【ラビリンス】と共に迷宮を冒険\nするための遺物。マスターの⼒を\n冠した剣は、開発者権限の⼀部を\n解放し、遺物を即座に獲得する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ヴォイスフォーユー", 4, 0, 50006, 50006, "30秒ごとに物理/魔法攻撃力ダウン解除", 3200, 10, 3, 1, "【カルミナ】と共に迷宮を冒険す\nるための遺物。ハンドマイクを通\nじて拡がっていく歌声は、味方の\n疲労をふき飛ばす。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ディアボロスフィアー", 1, 0, 50007, 50007, "15秒ごとにＴＰ固定量100回復\n敵のＴＰ100ダウン", 3200, 10, 3, 1, "【悪魔偽王国軍】と共に迷宮を冒\n険するための遺物。重く振りかざ\nす一撃は、斬り裂いた獲物の生気\nを我が物とする。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ドングリースピリット", 5, 0, 50008, 50008, "行動不能無効１回", 3200, 10, 3, 1, "【牧場】と共に迷宮を冒険するた\nめの遺物。持ち主のやる気を呼び\n起こし、ぐうたらさを１回だけ無\n効化できる。あくまで１回だけ。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("リヴァイアサンコール", 3, 0, 50009, 50009, "物理/魔法クリダメアップ（アルファルピ所持数×0.01%、最大100%）", 3200, 10, 3, 1, "【メルクリウス財団】と共に迷宮\nを冒険するための遺物。富を積め\nば積むほど精神を集中させ、必殺\nの一突きを敵に見舞う。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("バインディングローズ", 2, 0, 50010, 50010, "敵への継続ダメージアップ（加入キャラ数×10％、最大50万ダメージ）", 3200, 10, 3, 1, "【トワイライトキャラバン】と共\nに迷宮を冒険するための遺物。さ\nまざまな者たちの個性を学習し、\n敵を苦しめる術に転化する。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("トリックランナー", 0, 1, 50011, 50011, "コネクトサインマスの抽選回数+1（1回）", 3200, 10, 3, 0, "【リトルリリカル】と共に迷宮を\n冒険するための遺物。履くと元気\nが溢れ出し、走り回ってより多く\nの仲間を勧誘できる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("姫さま親衛隊勧誘係", 0, 3, 50012, 50012, "バトル勝利後時の仲間キャラ加入数+1（3回）", 3200, 10, 3, 0, "【自警団】と共に迷宮を冒険する\nための遺物。姫さま親衛隊の精鋭\n隊員たちで、仲間をより増やすた\nめに日夜勤しんでいる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("フォーチュンミーティア", 0, 1, 50013, 50013, "迷宮遺物マスの抽選回数+1（1回）", 3200, 10, 3, 0, "【フォレスティエ】と共に迷宮を\n冒険するための遺物。きらりと輝\nく流れ星が、多くのアイテムを手\nに入れる幸運を呼び寄せる。");
INSERT INTO `v1_fcc702ed7e4bfb41a8fe34e9ded74f3abc5e72363610acd8be0dbffe84cb68ba` VALUES ("ベルベットルージュ", 0, 1, 50014, 50014, "敵の誘惑時間+50％", 3200, 10, 3, 0, "【ルーセント学院】と共に迷宮を\n冒険するための遺物。悪魔的なほ\nどに真紅の艶めきは、見た者の目\nを釘付けにし、二度と逃さない。");
